let raw = $json.output || "";

// If output is wrapped in markdown code blocks, extract it
if (raw.includes("```json")) {
  raw = raw.split("```json")[1].split("```")[0].trim();
} else if (raw.includes("```")) {
  raw = raw.split("```")[1].split("```")[0].trim();
}

// clean escape characters if needed
const cleaned = raw.replace(/\\n/g, "").replace(/\\"/g, '"').trim();

try {
  const parsed = JSON.parse(cleaned);
  return [
    {
      json: {
        movies: parsed
      }
    }
  ];
} catch (e) {
  try {
    const parsedRaw = JSON.parse(raw.trim());
    return [
      {
        json: {
          movies: parsedRaw
        }
      }
    ];
  } catch (e2) {
    return [
      {
        json: {
          error: "Invalid JSON",
          raw: raw,
          err: e2.message
        }
      }
    ];
  }
}
